from flask import Flask, redirect, url_for, session, request
import requests
import os
import random
import string

app = Flask(__name__)
app.secret_key = os.urandom(24)

CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_URL = 'https://authorization.server/auth'
TOKEN_URL = 'https://authorization.server/token'
REDIRECT_URI = 'http://localhost:5000/callback'

def generate_state():
    return ''.join(random.choices(string.ascii_letters + string.digits, k=16))

@app.route('/login')
def login():
    state = generate_state()
    session['oauth_state'] = state
    authorization_url = f"{AUTHORIZATION_URL}?response_type=code&client_id={CLIENT_ID}&redirect_uri={REDIRECT_URI}&state={state}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    if request.args.get('state') != session.get('oauth_state'):
        return "State mismatch error", 400

    code = request.args.get('code')
    token_response = requests.post(TOKEN_URL, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    })

    if token_response.status_code == 200:
        session['access_token'] = token_response.json().get('access_token')
        return "Login successful"
    else:
        return "Token exchange failed", 400

if __name__ == '__main__':
    app.run(debug=True)